SELECT COUNT(SP.PK) AS TOTAL FROM SERVIDOR_PROJ SP JOIN PROJ P ON P.PK = SP.FK_PROJ JOIN SERVIDOR S ON S.PK_SIAPE = SP.FK_SIAPE WHERE LOWER(S.GENERO) = LOWER('feminino') AND LOWER(S.SIGLA_CAMPUS) = LOWER('luz') AND LOWER(SP.PAPEL) = LOWER('coordenador') AND LOWER(P.TIPO_PROJETO) = LOWER('ensino') AND SP.DATA_ENTRADA <= DATE('now') AND SP.DATA_SAIDA >= CAST(DATE('now', '-5 years') AS DATE)